const tag = "stackhub-22";

// 390個のデータを効率よく定義するためのヘルパー関数
function c(id, name, cat, score, baseMentions, desc, isAff = false, price = "", url = "", img = "") {
  const trendData = [
    Math.max(25, score - 10), Math.max(25, score - 5), Math.max(25, score - 8),
    Math.max(25, score - 2), Math.max(25, score - 4), Math.max(25, score - 3),
    Math.max(25, score + 2), Math.max(25, score - 1), score
  ];
  return {
    id, name, category: cat, trendScore: score,
    mentions24h: Math.round(baseMentions / 30),
    mentions7d: Math.round(baseMentions / 4),
    mentions30d: baseMentions,
    description: desc,
    isAffiliate: isAff,
    affiliatePrice: price,
    url: isAff ? url : (url || `https://github.com/${id}`),
    imageName: img,
    trendData
  };
}

